import psutil
from plyer import notification

def check_battery():
    battery = psutil.sensors_battery()
    if battery.percent < 20 and not battery.power_plugged:
        notification.notify(
            title='电量焦虑预警',
            message=f'电量仅剩{battery.percent}%，该充电了！',
            timeout=10
        )
